// Plasmo扩展：内容脚本核心逻辑
import { Storage } from "@plasmohq/storage"

const storage = new Storage()

// 监听高亮事件
document.addEventListener("mouseup", async () => {
  const selection = window.getSelection().toString()
  if (selection.length < 10) return

  // 获取当前页面信息
  const pageMeta = { title: document.title, url: location.href }

  // 调用AI摘要API
  const summary = await fetch("https://api.yourservice.com/summarize", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text: selection, meta: pageMeta })
  }).then(r => r.json())

  // 保存到本地存储 + 同步云端
  await storage.set(`highlight_${Date.now()}`, { selection, summary, ...pageMeta })
})

# AI SDR 核心：目标客户档案 + 个性化文案
import requests
from browser_use import Agent
import anthropic

class AISDR:
    def __init__(self):
        self.claude = anthropic.Anthropic()

    def build_profile(self, company_url: str):
        agent = Agent(task=f"抓取 {company_url} 的关于我们、产品页、招聘页、新闻页，提取关键信息")
        raw = agent.run()
        profile = self.claude.messages.create(
            model="claude-4-opus",
            max_tokens=1000,
            messages=[{"role":"user","content":f"将以下信息整理为结构化客户档案：{raw}"}]
        )
        return profile.content[0].text

    def generate_email(self, profile: str, product: str):
        prompt = f"基于客户档案：{profile}
产品：{product}
请撰写Cold Email（100字以内）。"
        resp = self.claude.messages.create(model="claude-4-opus", max_tokens=300, messages=[{"role":"user","content":prompt}])
        return resp.content[0].text

# Stripe 订阅收款核心（Next.js API Route）
import Stripe from 'stripe'
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY)

export default async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).end()
  const { email, priceId } = req.body
  const customer = await stripe.customers.create({ email })
  const subscription = await stripe.subscriptions.create({
    customer: customer.id,
    items: [{ price: priceId }],
    payment_behavior: 'default_incomplete',
    expand: ['latest_invoice.payment_intent'],
  })
  res.json({ clientSecret: subscription.latest_invoice.payment_intent.client_secret })
}
